const items = $input.all();
const prices = [];
const seen = new Set();

function cleanText(t) {
  return (t || '').replace(/\s+/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&#[0-9]+;/g, '').trim();
}

function detectSource(html) {
  const lower = (html || '').toLowerCase();
  if (lower.includes('bigmat.es')) return { name: 'BigMat', website: 'https://www.bigmat.es' };
  if (lower.includes('porcelanosa.com')) return { name: 'Porcelanosa', website: 'https://www.porcelanosa.com' };
  if (lower.includes('roca.es')) return { name: 'Roca', website: 'https://www.roca.es' };
  if (lower.includes('bauhaus.es')) return { name: 'Bauhaus', website: 'https://www.bauhaus.es' };
  if (lower.includes('bricoking.es')) return { name: 'Bricoking', website: 'https://www.bricoking.es' };
  if (lower.includes('grupopuma.com')) return { name: 'Grupo Puma', website: 'https://www.grupopuma.com' };
  return { name: 'Proveedor Web', website: '' };
}

function detectCategory(title) {
  const t = (title || '').toLowerCase();
  if (/cement|mortero|yeso|escayola|hormig/i.test(t)) return 'albanileria';
  if (/azulejo|baldosa|porcelan|ceramica|gres/i.test(t)) return 'revestimientos';
  if (/grifo|ducha|inodoro|lavabo|mampara|bañera|sanitario/i.test(t)) return 'fontaneria';
  if (/pintura|barniz|esmalte|imprimacion/i.test(t)) return 'pintura';
  if (/madera|tablero|panel|tarima|parquet/i.test(t)) return 'madera';
  if (/tubo|tuberia|codo|manguito|valvula/i.test(t)) return 'instalaciones';
  if (/ladrillo|bloque|rasilla|termoarcilla/i.test(t)) return 'obra_gruesa';
  if (/aislamiento|lana|poliestireno|xps|eps/i.test(t)) return 'aislamiento';
  if (/puerta|ventana|persiana|cerradura/i.test(t)) return 'carpinteria';
  if (/cable|enchufe|interruptor|cuadro|led/i.test(t)) return 'electricidad';
  return 'general';
}

function detectUnit(title) {
  const t = (title || '').toLowerCase();
  if (/\/m2|por m2|metro cuadrado/i.test(t)) return 'm2';
  if (/\/ml|metro lineal/i.test(t)) return 'ml';
  if (/saco|bolsa/i.test(t)) return 'saco';
  if (/kg|kilo/i.test(t)) return 'kg';
  if (/litro|lt/i.test(t)) return 'l';
  return 'ud';
}

for (const item of items) {
  const html = item.json.data || item.json.body || '';
  if (!html || html.length < 100) continue;

  const source = detectSource(html);

  // Strategy 1: JSON-LD
  const jsonLdBlocks = html.match(/<script type="application\/ld\+json">[\s\S]*?<\/script>/g) || [];
  for (const block of jsonLdBlocks) {
    try {
      const jsonStr = block.replace(/<script[^>]*>/, '').replace(/<\/script>/, '').trim();
      const data = JSON.parse(jsonStr);
      const products = data['@type'] === 'ItemList' ? (data.itemListElement || []).map(i => i.item || i) : data['@type'] === 'Product' ? [data] : [];
      for (const p of products) {
        if (!p.name || !p.offers) continue;
        const offer = Array.isArray(p.offers) ? p.offers[0] : p.offers;
        const price = parseFloat(offer.price);
        if (!price || price <= 0 || price > 50000) continue;
        const name = cleanText(p.name);
        const key = `${name}|${source.name}`;
        if (seen.has(key)) continue;
        seen.add(key);
        prices.push({
          name: name.substring(0, 160),
          sku: p.sku || p.productID || '',
          brand: p.brand?.name || '',
          price,
          unit: detectUnit(name),
          url: p.url || '',
          category: detectCategory(name),
          is_available: offer.availability ? offer.availability.includes('InStock') : true,
          _source: source.name
        });
      }
    } catch(e) { /* skip */ }
  }

  // Strategy 2: Price pattern matching
  const priceBlocks = html.match(/.{0,300}(\d{1,4}[.,]\d{2})\s*(?:€|&euro;|EUR).{0,100}/gi) || [];
  for (const block of priceBlocks.slice(0, 100)) {
    const priceMatch = block.match(/(\d{1,4}[.,]\d{2})\s*(?:€|&euro;|EUR)/i);
    if (!priceMatch) continue;
    const value = parseFloat(priceMatch[1].replace(',', '.'));
    if (!value || value <= 0.5 || value > 50000) continue;

    const titleMatch = block.match(/(?:title|alt|data-name|aria-label|product-name)[="':>\s]*([^"<>|]{8,140})/i)
      || block.match(/>([^<>]{10,120})</);
    if (!titleMatch) continue;

    const name = cleanText(titleMatch[1]);
    if (name.length < 8 || /cookie|politi|legal|pago|envio|devolu/i.test(name)) continue;

    const key = `${name}|${source.name}`;
    if (seen.has(key)) continue;
    seen.add(key);

    prices.push({
      name: name.substring(0, 160),
      price: Number(value.toFixed(2)),
      unit: detectUnit(name),
      category: detectCategory(name),
      is_available: true,
      _source: source.name
    });
  }
}

// Group by provider for webhook
const byProvider = {};
for (const p of prices) {
  const src = p._source || 'Proveedor Web';
  if (!byProvider[src]) byProvider[src] = [];
  delete p._source;
  byProvider[src].push(p);
}

const batches = Object.entries(byProvider).map(([provName, items]) => ({
  action: 'upsert_products',
  source: { name: `n8n-${provName.toLowerCase().replace(/\s+/g, '-')}-scraper`, type: 'n8n_webhook', url: items[0]?.url || '' },
  provider: { name: provName, region: 'ES' },
  items,
  metadata: { scraped_at: new Date().toISOString(), workflow_id: 'proveedores-extra', n8n_execution_id: $execution.id }
}));

if (batches.length === 0) {
  return [{ json: { _empty: true, message: 'No se encontraron productos. Las webs pueden estar bloqueando scraping.' } }];
}

return batches.map(b => ({ json: b }));

const response = $input.first().json;
const summary = {
  ok: response.ok,
  provider: response.provider_id,
  created: response.created || 0,
  updated: response.updated || 0,
  errors: response.errors?.length || 0,
  duration_ms: response.duration_ms || 0
};
console.log('ENLAZE PB webhook:', JSON.stringify(summary));
return [{ json: summary }];
